settings.liquid:
{% comment %}
  Product Page Breadcrumbs
  Includes: Home > Collection (if exists) > Product
{% endcomment %}

<nav class="breadcrumb" aria-label="Breadcrumb">
  <ol class="breadcrumb__list">
    {%- comment -%} Home Link {%- endcomment -%}
    <li class="breadcrumb__item">
      <a href="{{ routes.root_url }}" class="breadcrumb__link">
        <span>Home</span>
      </a>
    </li>

    {%- comment -%} Collection Link (if product is in a collection) {%- endcomment -%}
    {% if collection %}
      <li class="breadcrumb__item">
        <span class="breadcrumb__separator" aria-hidden="true">/</span>
        <a href="{{ collection.url }}" class="breadcrumb__link">
          <span>{{ collection.title }}</span>
        </a>
      </li>
    {% endif %}

    {%- comment -%} Current Product {%- endcomment -%}
    <li class="breadcrumb__item">
      <span class="breadcrumb__separator" aria-hidden="true">/</span>
      <a href="{{ product.url }}" class="breadcrumb__link" aria-current="page">
        <span>{{ product.title }}</span>
      </a>
    </li>
  </ol>
</nav>

<style>
  /* Breadcrumb Container */
  .breadcrumb {
    margin: 0rem 0;
    padding:  0 30px;
  }

  /* Breadcrumb List */
  .breadcrumb__list {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    list-style: none;
    margin: 0;
    padding: 0;
    gap: 0.5rem;
  }

  /* Breadcrumb Items */
  .breadcrumb__item {
    display: flex;
    align-items: center;
    font-size: 0.875rem;
    line-height: 1.5;
  }

  /* Breadcrumb Links */
  .breadcrumb__link {
    color: #666;
    text-decoration: none;
    transition: color 0.2s ease;
    word-break: break-word;
  }

  .breadcrumb__link:hover {
    color: #000;
    text-decoration: underline;
  }

  /* Current Page */
  .breadcrumb__link[aria-current="page"] {
    color: #333;
    font-weight: 500;
    pointer-events: none;
  }

  /* Separator */
  .breadcrumb__separator {
    margin: 0 0.5rem;
    color: #999;
    user-select: none;
  }

  /* Mobile Optimization */
  @media (max-width: 768px) {
    .breadcrumb {
      margin: 0.75rem 0;
      padding: 0.5rem 0;
    }

    .breadcrumb__item {
      font-size: 0.8125rem;
    }

    .breadcrumb__separator {
      margin: 0 0.375rem;
    }

    /* Truncate long product titles on mobile */
    .breadcrumb__link[aria-current="page"] span {
      display: inline-block;
      max-width: 150px;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
      vertical-align: bottom;
    }
  }

  /* Extra Small Devices */
  @media (max-width: 480px) {
    .breadcrumb__item {
      font-size: 0.75rem;
    }

    .breadcrumb__separator {
      margin: 0 0.25rem;
    }
  }

  /* Tablet and Desktop */
  @media (min-width: 769px) {
    .breadcrumb {
      margin: 1.5rem 0;
    }
  }
</style>

{%- assign jdgm_data = product.metafields.judgeme.review_widget_data.value -%}
{%- assign star_rating = jdgm_data.average_rating -%}
{%- assign star_count = jdgm_data.number_of_reviews -%}

{%- if star_rating != blank and star_rating != '0' and star_count != blank and star_count > 0 -%}
  <style>
    .star_avg_rating_class {
      display: flex;
      line-height: 1;
      border-radius: 5px;
      height: 22px;
      gap: 3px;
      width: max-content;
      align-items: center;
      text-decoration: none;
    }

    .star_avg_rating_class__pill {
      display: flex;
      align-items: center;
      gap: 4px;
      background: #4ce279;
      color: #000;
      font-size: 13px;
      font-weight: 500;
      padding: 5px 6px 5px 5px;
      border-radius: 5px;
      height: 22px;
      line-height: 1;
    }

    .star_avg_rating_class__count {
      font-size: 13px;
      color: var(--color-text-secondary);
    }
  </style>

  <a href="#judgeme_product_reviews" class="star_avg_rating_class">
    <span class="star_avg_rating_class__pill">
      <svg width="11" height="11" viewBox="0 0 12 12" fill="currentColor" aria-hidden="true">
        <path d="M6 0l1.5 3.5 3.8.4-2.8 2.6.8 3.8L6 8.6l-3.3 1.7.8-3.8L.7 3.9l3.8-.4z"/>
      </svg>
      {{ star_rating }}
    </span>
    {%- if star_count != blank and star_count != '0' -%}
      <span class="star_avg_rating_class__count">({{ star_count }})</span>
    {%- endif -%}
  </a>
{%- endif -%}

{% assign bundle_products = product.metafields.custom.product_catagories_mention.value %}
{% if bundle_products and bundle_products.size > 0 %}

<style>
  .fera-bundle {
    display: flex;
    align-items: stretch;
    justify-content: center;
    gap: 10px;
    margin: 0 0 24px 0;
    width: 100%;
  }

  .fera-bundle-card {
    flex: 1;
    max-width: 140px;
    border-radius: 14px;
    overflow: hidden;
    display: block;
    text-decoration: none;
    position: relative;
    aspect-ratio: 3 / 4;
    background: #e8e0d8;
    box-shadow:
      0 0 0 2px #ffffff,
      0 0 0 3.5px #c0392b;
    opacity: 0;
    transform: translateY(8px);
    animation: feraBundleIn 0.4s cubic-bezier(0.25, 1, 0.5, 1) forwards;
  }

  .fera-bundle-card:nth-child(1) { animation-delay: 0.05s; }
  .fera-bundle-card:nth-child(2) { animation-delay: 0.13s; }
  .fera-bundle-card:nth-child(3) { animation-delay: 0.21s; }

  @keyframes feraBundleIn {
    to { opacity: 1; transform: translateY(0); }
  }

  .fera-bundle-card img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    object-position: center;
    display: block;
    transition: transform 0.35s ease;
  }

  .fera-bundle-card:hover img {
    transform: scale(1.05);
  }

  /* shimmer loading state */
  .fera-bundle-card::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(90deg, #e8e0d8 25%, #f0e8e0 50%, #e8e0d8 75%);
    background-size: 200% 100%;
    animation: feraShimmer 1.4s infinite;
    z-index: 1;
    transition: opacity 0.3s;
  }

  .fera-bundle-card.loaded::before {
    opacity: 0;
    pointer-events: none;
  }

  @keyframes feraShimmer {
    0%   { background-position: 200% 0; }
    100% { background-position: -200% 0; }
  }

  .fera-bundle-card img {
    position: relative;
    z-index: 2;
  }

  /* label at bottom */
  .fera-bundle-label {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 3;
    background: linear-gradient(to top, rgba(42,33,24,0.72) 0%, transparent 100%);
    padding: 18px 8px 8px;
    font-family: 'Helvetica Neue', Arial, sans-serif;
    font-size: 9px;
    font-weight: 500;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: #f7f3ee;
    text-align: center;
    line-height: 1.3;
  }

  @media (min-width: 768px) {
    .fera-bundle {
      gap: 14px;
    }
    .fera-bundle-card {
      max-width: 160px;
    }
    .fera-bundle-label {
      font-size: 10px;
    }
  }

 .fera-bundle-header {
    margin: 0 0 12px 0;
  }

  .fera-bundle-tag {
    display: block;
    font-family: 'Helvetica Neue', Arial, sans-serif;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    color: #c0392b;
    margin-bottom: 4px;
  }

  .fera-bundle-sub {
    font-family: 'Helvetica Neue', Arial, sans-serif;
    font-size: 13px;
    font-weight: 400;
    color: #8c7b6b;
    letter-spacing: 0.02em;
  }

</style>




<div class="fera-bundle-header">
  <span class="fera-bundle-tag">This combo includes</span>
  <p class="fera-bundle-sub">Tap any product to know more</p>
</div>

<div class="fera-bundle">
  {% for bp in bundle_products limit: 3 %}
    <a class="fera-bundle-card" href="{{ bp.url }}" aria-label="{{ bp.title }}">
      <img
        src="{{ bp.featured_image | image_url: width: 400 }}"
        alt="{{ bp.title }}"
        loading="lazy"
        onload="this.closest('.fera-bundle-card').classList.add('loaded')"
        onerror="this.closest('.fera-bundle-card').classList.add('loaded')"
      />
      <span class="fera-bundle-label">{{ bp.title | split: '|' | first | strip }}</span>
    </a>
  {% endfor %}
</div>

{% endif %}

{%- if product.metafields.custom.products_short_info != blank -%}
  <div class="product-short-info">
    {{ product.metafields.custom.products_short_info | metafield_tag }}
  </div>
{%- endif -%}

<style>
  .product-short-info p {
    font-weight: 500;
    font-size: 14px;
    line-height: 146%;
    margin: 0 0 4px;
  }
</style>

{% if product.metafields.custom.features.value %}
  <style>
    .pf-feature-wrap {
      margin: 10px 0 18px;
    }

    .pf-feature-title {
      font-size: 14px;
      font-weight: 800;
      color: #1c1c1c;
      margin: 0 0 10px;
    }

    .pf-feature-title span {
      color: #ff2834;
    }

    .pf-feature-grid {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
      margin: 0 0 10px;
    }

    .pf-feature-chip {
      display: inline-flex;
      align-items: center;
      padding: 10px 14px;
      border-radius: 12px;
      background: #f2f2f2;
      font-size: 14px;
      font-weight: 500;
      color: #1c1c1c;
      white-space: nowrap;
    }

    .pf-feature-chip:first-child {
      background: #fff0f1;
      color: #ff2834;
      border: 1px solid #ff2834;
    }

    .pf-feature-chip--hidden {
      display: none;
    }

    .pf-view-more {
      background: none;
      border: none;
      font-size: 13px;
      font-weight: 500;
      color: #ff2834;
      cursor: pointer;
      padding: 4px 0;
      text-decoration: none;
      display: inline-flex;
      align-items: center;
      gap: 4px;
      letter-spacing: 0.02em;
    }

    .pf-view-more__arrow {
      display: inline-block;
      font-size: 16px;
      transition: transform 0.2s ease;
    }

    .pf-view-more.is-open .pf-view-more__arrow {
      transform: rotate(180deg);
    }

    @media (max-width: 480px) {
      .pf-feature-chip {
        font-size: 10px;
        padding: 8px 12px;
      }
    }
  </style>

  {% assign features = product.metafields.custom.features.value %}

  <div class="pf-feature-wrap">
    <p class="pf-feature-title">Key <span>Ingredients</span></p>
    <div class="pf-feature-grid" id="pf-grid">
      {% for feature in features %}
        <div class="pf-feature-chip {% if forloop.index > 7 %}pf-feature-chip--hidden{% endif %}">
          {{ feature | strip }}
        </div>
      {% endfor %}
    </div>
    {% if features.size > 7 %}
      <button class="pf-view-more" id="pf-toggle">
        <span class="pf-view-more__text">See all ingredients</span>
        <span class="pf-view-more__arrow">›</span>
      </button>
    {% endif %}
  </div>

  {% if features.size > 7 %}
    <script>
      (function() {
        var btn = document.getElementById('pf-toggle');
        var grid = document.getElementById('pf-grid');
        var isOpen = false;

        btn.addEventListener('click', function() {
          isOpen = !isOpen;
          var chips = grid.querySelectorAll('.pf-feature-chip');

          chips.forEach(function(chip, i) {
            if (i >= 7) {
              chip.style.display = isOpen ? 'inline-flex' : 'none';
            }
          });

          btn.querySelector('.pf-view-more__text').textContent = isOpen ? 'Show less' : 'See all ingredients';
          btn.classList.toggle('is-open', isOpen);
        });
      })();
    </script>
  {% endif %}
{% endif %}

{% assign notes = product.metafields.custom.notes.value %}
{% if notes != blank %}
  <div class="notes-block">
    <div class="notes-content-wrap">
      <div class="notes-title">NOTES</div>
      <div class="notes-slider-wrap">
        <button class="notes-arrow notes-prev" type="button" aria-label="Previous notes">‹</button>
        <div class="notes-slider" data-notes-slider>
          {% for file in notes %}
            {% assign img = file | image_url: width: 240 %}
            <div class="notes-item">
              <div class="notes-img">
                <img
                  src="{{ img }}"
                  alt="{{ file.alt | default: 'Note' }}"
                  loading="lazy"
                  width="120"
                  height="120"
                >
              </div>
              {%- comment -%}
                If you don't have labels, we can try using alt text.
                Add alt text to the file in Shopify admin for best results.
              {%- endcomment -%}
              <div class="notes-label">{{ file.alt | default: '' }}</div>
            </div>
          {% endfor %}
        </div>
        <button class="notes-arrow notes-next" type="button" aria-label="Next notes">›</button>
        <div class="notes-fade-overlay"></div>
      </div>
    </div>
  </div>
  <style>
    .notes-block { margin: 16px 0; }
    .notes-content-wrap { display: flex; flex-direction: column; gap: 10px; }
    .notes-title { font-size: 12px; letter-spacing: .12em; text-transform: uppercase; }
    .notes-slider-wrap { 
      position: relative; 
      display: flex; 
      align-items: center; 
      gap: 8px; 
    }
    .notes-arrow{
      border: 0; background: transparent; cursor: pointer;
      font-size: 22px; line-height: 1; padding: 6px 10px;
    }
    .notes-slider{
      display: flex;
      gap: 18px;
      overflow-x: auto;
      scroll-snap-type: x mandatory;
      -webkit-overflow-scrolling: touch;
      scrollbar-width: none;
      padding: 2px 2px 8px;
      width: 100%;
    }
    .notes-slider::-webkit-scrollbar{ display:none; }
    .notes-item{ flex: 0 0 auto; scroll-snap-align: start; text-align: center; }
    .notes-img{
      width: 74px; height: 74px; 
      border-radius: 5px;
      overflow: hidden;
      background: #f3f3f3;
      display: grid; place-items: center;
      border: 1px solid #AC1D21;
    }
    .notes-img img{ width: 100%; height: 100%; object-fit: cover; display:block; }
    .notes-label{
      margin-top: 8px;
      font-size: 12px;
      line-height: 1.2;
      white-space: nowrap;
    }
    .notes-fade-overlay {
      display: none;
    }

    /* Mobile styles */
    @media (max-width: 480px){
      .notes-content-wrap { 
        display: flex; 
        flex-direction: row; 
        align-items: center; 
        gap: 12px; 
      }
      .notes-title { 
        flex-shrink: 0;
        writing-mode: horizontal-tb;
        min-width: fit-content;
      }
      .notes-slider-wrap {
        flex: 1;
        min-width: 0;
      }
      .notes-img{ width: 62px; height: 62px; }
      .notes-slider{ 
        gap: 14px;
        scroll-snap-type: none;
      }
      .notes-arrow{ display: none; }

      /* Fade overlay on the right side */
      .notes-fade-overlay {
        display: block;
        position: absolute;
        right: 0;
        top: 0;
        bottom: 8px;
        width: 40px;
        background: linear-gradient(to left, rgba(255, 255, 255, 0.95) 0%, rgba(255, 255, 255, 0) 100%);
        pointer-events: none;
        z-index: 1;
      }
    }
  </style>
  <script>
    (function(){
      const slider = document.querySelector('[data-notes-slider]');
      if(!slider) return;
      const prev = slider.parentElement.querySelector('.notes-prev');
      const next = slider.parentElement.querySelector('.notes-next');
      function scrollByCard(dir){
        const firstItem = slider.querySelector('.notes-item');
        if(!firstItem) return;
        const gap = parseFloat(getComputedStyle(slider).gap || 0);
        const step = firstItem.getBoundingClientRect().width + gap;
        slider.scrollBy({ left: dir * step, behavior: 'smooth' });
      }
      prev && prev.addEventListener('click', () => scrollByCard(-1));
      next && next.addEventListener('click', () => scrollByCard(1));
    })();
  </script>
{% endif %}

