<div class="hc-b2g1-wrap">

  <div class="hc-b2g1-banner">
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="#AC1D21" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
      <path d="M20.59 13.41l-7.17 7.17a2 2 0 0 1-2.83 0L2 12V2h10l8.59 8.59a2 2 0 0 1 0 2.82z"/>
      <line x1="7" y1="7" x2="7.01" y2="7"/>
    </svg>
    <span>Create Your Own Combo — Buy 2, Get 1 Absolutely Free</span>
  </div>

  <div class="hc-b2g1 hc-b2g1--open" id="hc-b2g1-{{ section.id }}">

    <div class="hc-b2g1__header" onclick="document.getElementById('hc-b2g1-{{ section.id }}').classList.toggle('hc-b2g1--open');">
      <div class="hc-b2g1__header-left">
        <span class="hc-b2g1__pulse"></span>
        <span class="hc-b2g1__tag">Buy 2 Get 1 Free</span>
        <span class="hc-b2g1__title">Add 3, pay for 2</span>
      </div>
      <div class="hc-b2g1__header-right">
        <span class="hc-b2g1__savings" id="hc-b2g1-savings-{{ section.id }}"></span>
        <svg class="hc-b2g1__chevron" viewBox="0 0 16 16">
          <path d="M3 6l5 5 5-5"/>
        </svg>
      </div>
    </div>

    <div class="hc-b2g1__body">
      <div class="hc-b2g1__items">

        {%- comment -%} FREE ITEM {%- endcomment -%}
        <div class="hc-b2g1__item hc-b2g1__item--free">
          <div class="hc-b2g1__item-num">1</div>
          {%- if fp1.featured_image -%}
            <img
              class="hc-b2g1__item-img"
              src="{{ fp1.featured_image | image_url: width: 128 }}"
              alt="{{ fp1.title | escape }}"
              width="64"
              height="64"
              loading="lazy"
            >
          {%- endif -%}
          <div class="hc-b2g1__item-middle">
            <div class="hc-b2g1__item-name" id="hc-b2g1-fname-{{ section.id }}">{{ fp1.title }}</div>
            <span class="hc-b2g1__free-badge">Free Item</span>
            {%- if fp2 -%}
              <select id="hc-b2g1-fp-{{ section.id }}" onchange="hcB2G1FreeProductChange('{{ section.id }}')">
                <option value="fp1">{{ fp1.title }}</option>
                <option value="fp2">{{ fp2.title }}</option>
              </select>
            {%- endif -%}
          </div>
          <div class="hc-b2g1__item-right">
            <div class="hc-b2g1__item-price-wrap">
              <span class="hc-b2g1__item-price--strike" id="hc-b2g1-fp1-{{ section.id }}">{{ fp1_cheapest.price | money }}</span>
              <span class="hc-b2g1__item-free-tag">FREE</span>
            </div>
          </div>
        </div>

        {%- comment -%} PAID ITEM 2 {%- endcomment -%}
        <div class="hc-b2g1__item">
          <div class="hc-b2g1__item-num">2</div>
          {%- if product.featured_image -%}
            <img
              class="hc-b2g1__item-img"
              id="hc-b2g1-img2-{{ section.id }}"
              src="{{ product.featured_image | image_url: width: 128 }}"
              alt="{{ product.title | escape }}"
              width="64"
              height="64"
              loading="lazy"
            >
          {%- endif -%}
          <div class="hc-b2g1__item-middle">
            <div class="hc-b2g1__item-name" id="hc-b2g1-name2-{{ section.id }}">{{ product.title }}</div>
            <select id="hc-b2g1-pp2-{{ section.id }}" onchange="hcB2G1ProductChange('{{ section.id }}', 2)">
              <option value="main">{{ product.title }}</option>
              {%- if p2 and p2.handle != product.handle -%}
                <option value="p2">{{ p2.title }}</option>
              {%- endif -%}
              {%- if p3 and p3.handle != product.handle -%}
                <option value="p3">{{ p3.title }}</option>
              {%- endif -%}
              {%- if p4 and p4.handle != product.handle -%}
                <option value="p4">{{ p4.title }}</option>
              {%- endif -%}
            </select>
            <select id="hc-b2g1-v2-{{ section.id }}" onchange="hcB2G1Update('{{ section.id }}')">
              {%- for variant in product.variants -%}
                <option value="{{ variant.id }}" data-price="{{ variant.price }}" {% if variant == current_variant %}selected{% endif %} {% unless variant.available %}disabled{% endunless %}>{{ variant.title }}</option>
              {%- endfor -%}
            </select>
          </div>
          <div class="hc-b2g1__item-right">
            <div class="hc-b2g1__item-price-wrap">
              <span class="hc-b2g1__item-price" id="hc-b2g1-p2-{{ section.id }}">{{ current_variant.price | money }}</span>
            </div>
          </div>
        </div>

        {%- comment -%} PAID ITEM 3 {%- endcomment -%}
        <div class="hc-b2g1__item">
          <div class="hc-b2g1__item-num">3</div>
          {%- if product.featured_image -%}
            <img
              class="hc-b2g1__item-img"
              id="hc-b2g1-img3-{{ section.id }}"
              src="{{ product.featured_image | image_url: width: 128 }}"
              alt="{{ product.title | escape }}"
              width="64"
              height="64"
              loading="lazy"
            >
          {%- endif -%}
          <div class="hc-b2g1__item-middle">
            <div class="hc-b2g1__item-name" id="hc-b2g1-name3-{{ section.id }}">{{ product.title }}</div>
            <select id="hc-b2g1-pp3-{{ section.id }}" onchange="hcB2G1ProductChange('{{ section.id }}', 3)">
              <option value="main">{{ product.title }}</option>
              {%- if p2 and p2.handle != product.handle -%}
                <option value="p2">{{ p2.title }}</option>
              {%- endif -%}
              {%- if p3 and p3.handle != product.handle -%}
                <option value="p3">{{ p3.title }}</option>
              {%- endif -%}
              {%- if p4 and p4.handle != product.handle -%}
                <option value="p4">{{ p4.title }}</option>
              {%- endif -%}
            </select>
            <select id="hc-b2g1-v3-{{ section.id }}" onchange="hcB2G1Update('{{ section.id }}')">
              {%- for variant in product.variants -%}
                <option value="{{ variant.id }}" data-price="{{ variant.price }}" {% if variant == current_variant %}selected{% endif %} {% unless variant.available %}disabled{% endunless %}>{{ variant.title }}</option>
              {%- endfor -%}
            </select>
          </div>
          <div class="hc-b2g1__item-right">
            <div class="hc-b2g1__item-price-wrap">
              <span class="hc-b2g1__item-price" id="hc-b2g1-p3-{{ section.id }}">{{ current_variant.price | money }}</span>
            </div>
          </div>
        </div>

      </div>

      <div class="hc-b2g1__footer">
        <div class="hc-b2g1__summary">
          <div>
            <div class="hc-b2g1__total-label">Total</div>
            <div class="hc-b2g1__total-prices">
              <span class="hc-b2g1__total-original" id="hc-b2g1-orig-{{ section.id }}"></span>
              <span class="hc-b2g1__total-final" id="hc-b2g1-final-{{ section.id }}"></span>
            </div>
          </div>
          <span class="hc-b2g1__save-badge" id="hc-b2g1-badge-{{ section.id }}"></span>
        </div>
        <button class="hc-b2g1__btn" id="hc-b2g1-btn-{{ section.id }}" onclick="hcB2G1AddToCart('{{ section.id }}')">
          Add All 3 — Pay for 2
        </button>
        <p class="hc-b2g1__note">Discount applied automatically at checkout</p>
      </div>

    </div>
  </div>
</div>

<script>
(function() {
  var sid = '{{ section.id }}';

  var PRODUCT_IMAGES = {
    main: {{ product.featured_image | image_url: width: 128 | json }},
    p2:   {{ p2.featured_image | image_url: width: 128 | json }},
    p3:   {{ p3.featured_image | image_url: width: 128 | json }},
    p4:   {{ p4.featured_image | image_url: width: 128 | json }}
  };

  var PRODUCTS = {
    main: {
      title: {{ product.title | json }},
      variantData: [
        {%- for v in product.variants -%}
          {id:{{ v.id }},title:{{ v.title | json }},price:{{ v.price }},available:{{ v.available }}}{% unless forloop.last %},{% endunless %}
        {%- endfor -%}
      ]
    }
    {%- if p2 and p2.handle != product.handle -%}
    ,p2: {
      title: {{ p2.title | json }},
      variantData: [
        {%- for v in p2.variants -%}
          {id:{{ v.id }},title:{{ v.title | json }},price:{{ v.price }},available:{{ v.available }}}{% unless forloop.last %},{% endunless %}
        {%- endfor -%}
      ]
    }
    {%- endif -%}
    {%- if p3 and p3.handle != product.handle -%}
    ,p3: {
      title: {{ p3.title | json }},
      variantData: [
        {%- for v in p3.variants -%}
          {id:{{ v.id }},title:{{ v.title | json }},price:{{ v.price }},available:{{ v.available }}}{% unless forloop.last %},{% endunless %}
        {%- endfor -%}
      ]
    }
    {%- endif -%}
    {%- if p4 and p4.handle != product.handle -%}
    ,p4: {
      title: {{ p4.title | json }},
      variantData: [
        {%- for v in p4.variants -%}
          {id:{{ v.id }},title:{{ v.title | json }},price:{{ v.price }},available:{{ v.available }}}{% unless forloop.last %},{% endunless %}
        {%- endfor -%}
      ]
    }
    {%- endif -%}
  };

  var FREE_PRODUCTS = {
    fp1: {
      title: {{ fp1.title | json }},
      cheapestVariant: (function(){
        var vd=[{%- for v in fp1.variants -%}{id:{{ v.id }},price:{{ v.price }},title:{{ v.title | json }},available:{{ v.available }}}{% unless forloop.last %},{% endunless %}{%- endfor -%}];
        return vd.sort(function(a,b){return a.price-b.price;})[0];
      })()
    }
    {%- if fp2 -%}
    ,fp2: {
      title: {{ fp2.title | json }},
      cheapestVariant: (function(){
        var vd=[{%- for v in fp2.variants -%}{id:{{ v.id }},price:{{ v.price }},title:{{ v.title | json }},available:{{ v.available }}}{% unless forloop.last %},{% endunless %}{%- endfor -%}];
        return vd.sort(function(a,b){return a.price-b.price;})[0];
      })()
    }
    {%- endif -%}
  };

  var currentFreeKey = 'fp1';

  function formatMoney(cents) {
    return 'Rs.\u00a0' + (cents/100).toLocaleString('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2});
  }

  function rebuildVariantSelect(slotNum, productKey) {
    var varSel = document.getElementById('hc-b2g1-v' + slotNum + '-' + sid);
    var nameEl = document.getElementById('hc-b2g1-name' + slotNum + '-' + sid);
    var imgEl  = document.getElementById('hc-b2g1-img' + slotNum + '-' + sid);
    var prod   = PRODUCTS[productKey];
    if (!prod) return;
    if (nameEl) nameEl.textContent = prod.title;
    if (imgEl && PRODUCT_IMAGES[productKey]) imgEl.src = PRODUCT_IMAGES[productKey];
    if (!varSel) return;
    varSel.style.display = prod.variantData.length <= 1 ? 'none' : '';
    varSel.innerHTML = '';
    prod.variantData.forEach(function(v) {
      var opt = document.createElement('option');
      opt.value = v.id;
      opt.setAttribute('data-price', v.price);
      opt.textContent = v.title;
      if (!v.available) opt.disabled = true;
      varSel.appendChild(opt);
    });
    update();
  }

  function getSlotVariant(slot) {
    var sel = document.getElementById('hc-b2g1-v' + slot + '-' + sid);
    if (!sel || !sel.options.length) return null;
    var opt = sel.options[sel.selectedIndex];
    return { id: parseInt(sel.value), price: parseInt(opt.getAttribute('data-price')) || 0 };
  }

  function getFreeVariant() {
    var fp = FREE_PRODUCTS[currentFreeKey];
    return fp ? fp.cheapestVariant : null;
  }

  function update() {
    var s2 = getSlotVariant(2);
    var s3 = getSlotVariant(3);
    var fv = getFreeVariant();
    if (!s2 || !s3 || !fv) return;

    var total3 = fv.price + s2.price + s3.price;
    var total2 = s2.price + s3.price;
    var saved  = fv.price;

    var p2El      = document.getElementById('hc-b2g1-p2-' + sid);
    var p3El      = document.getElementById('hc-b2g1-p3-' + sid);
    var fp1El     = document.getElementById('hc-b2g1-fp1-' + sid);
    var origEl    = document.getElementById('hc-b2g1-orig-' + sid);
    var finalEl   = document.getElementById('hc-b2g1-final-' + sid);
    var badgeEl   = document.getElementById('hc-b2g1-badge-' + sid);
    var savingsEl = document.getElementById('hc-b2g1-savings-' + sid);

    if (p2El)      p2El.textContent      = formatMoney(s2.price);
    if (p3El)      p3El.textContent      = formatMoney(s3.price);
    if (fp1El)     fp1El.textContent     = formatMoney(fv.price);
    if (origEl)    origEl.textContent    = formatMoney(total3);
    if (finalEl)   finalEl.textContent   = formatMoney(total2);
    if (badgeEl)   badgeEl.textContent   = 'Save ' + formatMoney(saved);
    if (savingsEl) savingsEl.textContent = 'Save ' + formatMoney(saved);
  }

  window.hcB2G1ProductChange = function(sectionId, slot) {
    if (sectionId !== sid) return;
    var ppSel = document.getElementById('hc-b2g1-pp' + slot + '-' + sid);
    if (!ppSel) return;
    rebuildVariantSelect(slot, ppSel.value);
  };

  window.hcB2G1FreeProductChange = function(sectionId) {
    if (sectionId !== sid) return;
    var fpSel = document.getElementById('hc-b2g1-fp-' + sid);
    if (!fpSel) return;
    currentFreeKey = fpSel.value;
    var fp = FREE_PRODUCTS[currentFreeKey];
    if (!fp) return;
    var nameEl = document.getElementById('hc-b2g1-fname-' + sid);
    if (nameEl) nameEl.textContent = fp.title;
    var fp1El = document.getElementById('hc-b2g1-fp1-' + sid);
    if (fp1El) fp1El.textContent = formatMoney(fp.cheapestVariant.price);
    update();
  };

  window.hcB2G1Update = function(sectionId) {
    if (sectionId === sid) update();
  };

  window.hcB2G1AddToCart = function(sectionId) {
    if (sectionId !== sid) return;
    var btn = document.getElementById('hc-b2g1-btn-' + sid);
    var s2  = getSlotVariant(2);
    var s3  = getSlotVariant(3);
    var fv  = getFreeVariant();
    if (!s2 || !s3 || !fv) return;

    btn.disabled = true;
    btn.textContent = 'Adding...';

    var counts = {};
    [fv.id, s2.id, s3.id].forEach(function(id) {
      counts[id] = (counts[id] || 0) + 1;
    });

    var items = Object.keys(counts).map(function(id) {
      return { id: parseInt(id), quantity: counts[id] };
    });

    var sectionsToBundle = [];
    document.documentElement.dispatchEvent(new CustomEvent('cart:prepare-bundled-sections', {
      bubbles: true,
      detail: { sections: sectionsToBundle }
    }));

    fetch((window.Shopify ? window.Shopify.routes.root : '/') + 'cart/add.js', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'X-Requested-With': 'XMLHttpRequest' },
      body: JSON.stringify({
        items: items,
        sections: sectionsToBundle.join(','),
        sections_url: window.location.pathname
      })
    })
    .then(function(r) { return r.json(); })
    .then(function(responseJson) {
      return fetch((window.Shopify ? window.Shopify.routes.root : '/') + 'cart.js')
        .then(function(r) { return r.json(); })
        .then(function(cartContent) {
          cartContent['sections'] = responseJson['sections'];
          var addedItems = responseJson.hasOwnProperty('items') ? responseJson['items'] : [responseJson];
          var vp   = document.querySelector('variant-picker[form-id]');
          var form = vp ? document.forms[vp.getAttribute('form-id')] : null;
          if (form) {
            form.dispatchEvent(new CustomEvent('variant:add', {
              bubbles: true,
              detail: { items: addedItems, cart: cartContent, onSuccessDo: null }
            }));
          }
          document.documentElement.dispatchEvent(new CustomEvent('cart:change', {
            bubbles: true,
            detail: { baseEvent: 'variant:add', cart: cartContent, onSuccessDo: null }
          }));
          btn.disabled = false;
          btn.textContent = 'Add All 3 \u2014 Pay for 2';
        });
    })
    .catch(function(err) {
      console.error('B2G1 error:', err);
      btn.disabled = false;
      btn.textContent = 'Add All 3 \u2014 Pay for 2';
    });
  };

  update();
})();
</script>

{% assign sections = product.metafields.custom.image_and_features.value %}

{% if sections != blank %}
  <section class="fera-ingredients">
