                  src="{{ item.image | image_url: width: 2000 }}"
                  srcset="{{ item.image | image_url: width: 800 }} 800w,
                          {{ item.image | image_url: width: 1200 }} 1200w,
                          {{ item.image | image_url: width: 1600 }} 1600w,
                          {{ item.image | image_url: width: 2000 }} 2000w"
                  sizes="(max-width: 768px) 100vw, (max-width: 1200px) 100vw, 1400px"
