{% assign faq_items = product.metafields.custom.faq.value %}
{% if faq_items != blank %}
  <section class="fera-faq">
    <div class="fera-faq__container">
      <header class="fera-faq__header">
        <span class="fera-faq__label">Questions</span>
        <h2 class="fera-faq__title">Frequently Asked</h2>
      </header>

      <div class="fera-faq__grid">
        {% for item in faq_items %}
          {% capture answer_html %}
            {{ item.description | metafield_tag }}
          {% endcapture %}

          <div class="fera-faq__item" data-faq-item>
            <button class="fera-faq__question"
                    type="button"
                    aria-expanded="false"
                    data-faq-trigger>
              <span class="fera-faq__question-text">{{ item.title }}</span>
              <span class="fera-faq__icon" aria-hidden="true">
                <svg class="fera-faq__icon-plus" width="20" height="20" viewBox="0 0 20 20" fill="none">
                  <path d="M10 4V16M4 10H16" stroke="currentColor" stroke-width="1.5" stroke-linecap="square"/>
                </svg>
                <svg class="fera-faq__icon-minus" width="20" height="20" viewBox="0 0 20 20" fill="none">
                  <path d="M4 10H16" stroke="currentColor" stroke-width="1.5" stroke-linecap="square"/>
                </svg>
              </span>
            </button>

            <div class="fera-faq__answer" data-faq-content>
              <div class="fera-faq__answer-inner">
                {{ answer_html }}
              </div>
            </div>
          </div>
        {% endfor %}
      </div>
    </div>
  </section>

  <script>
    document.addEventListener('DOMContentLoaded', function() {
      const faqItems = document.querySelectorAll('[data-faq-item]');

      faqItems.forEach(item => {
        const trigger = item.querySelector('[data-faq-trigger]');
        const content = item.querySelector('[data-faq-content]');

        if (!trigger || !content) return;

        trigger.addEventListener('click', () => {
          const isOpen = trigger.getAttribute('aria-expanded') === 'true';

          faqItems.forEach(otherItem => {
            if (otherItem !== item) {
              const otherTrigger = otherItem.querySelector('[data-faq-trigger]');
              const otherContent = otherItem.querySelector('[data-faq-content]');
              otherTrigger.setAttribute('aria-expanded', 'false');
              otherContent.style.maxHeight = '0px';
            }
          });

          if (isOpen) {
            trigger.setAttribute('aria-expanded', 'false');
            content.style.maxHeight = '0px';
          } else {
            trigger.setAttribute('aria-expanded', 'true');
            content.style.maxHeight = content.scrollHeight + 'px';
          }
        });
      });
    });
  </script>
{% endif %}

